const currentItem = HERO_CAROUSEL_ITEMS[activeSlide];

return (
  <Link
    className="flex items-stretch gap-5 overflow-clip transition-opacity hover:opacity-90"
    href={APP_ROUTES.BUYBACK_REQUESTS.CREATE}
  >
    {/* Square image — 152×152 */}
    <div className="relative h-[152px] w-[152px] shrink-0 overflow-hidden rounded-[4px]">
      <AnimatePresence mode="wait">
        <motion.div
          key={currentItem.id}
          animate={{ opacity: 1 }}
          className="absolute inset-0"
          exit={{ opacity: 0 }}
          initial={{ opacity: 0 }}
          transition={{ duration: 0.6, ease: "easeInOut" }}
        >
          <Image
            alt={currentItem.name}
            className="object-cover"
            fill
            sizes="152px"
            src={currentItem.imageSrc}
          />
        </motion.div>
      </AnimatePresence>
    </div>

    {/* Text */}
    <div className="flex w-[278px] flex-col justify-between overflow-hidden">
      <p className="font-new-sans text-[#F5F3EF] text-sm italic">
        Recently Quoted
      </p>

      {/* Slide progress bars — track is white/30, active segment fills 0→100% over 4 s */}
      <div className="flex items-center gap-1.5">
        {HERO_CAROUSEL_ITEMS.map((item, index) => (
          <button
            aria-label={`Go to slide ${index + 1}`}
            className="relative h-0.5 flex-1 bg-white/30 outline-none"
            key={`hero-dot-${item.id}`}
            onClick={(event) => {
              event.preventDefault();
              setActiveSlide(index);
            }}
            type="button"
          >
            {/* Past slides: instantly full */}
            {index < activeSlide && (
              <div className="absolute inset-0 bg-white" />
            )}
            {/* Active: width animates 0% → 100% over 4 s; key resets on slide change */}
            {index === activeSlide && (
              <motion.div
                animate={{ width: "100%" }}
                className="absolute left-0 top-0 h-full bg-white"
                initial={{ width: "0%" }}
                key={`progress-${activeSlide}`}
                transition={{ duration: 4, ease: "linear" }}
              />
            )}
          </button>
        ))}
      </div>

      <AnimatePresence mode="wait">
        <motion.div
          key={`hero-text-${currentItem.id}`}
          animate={{ opacity: 1, y: 0 }}
          className="flex flex-col gap-0.5"
          exit={{ opacity: 0, y: -4 }}
          initial={{ opacity: 0, y: 4 }}
          transition={{ duration: 0.4, ease: "easeOut" }}
        >
          {/* Fixed 48px height (2 lines × 16px × 1.5lh) — prevents layout shift */}
          <p className="h-[48px] overflow-hidden font-medium font-new-sans text-[#F5F3EF] text-base leading-normal">
            {currentItem.name}
          </p>
          <p className="font-extralight font-new-serif text-2xl text-[#F5F3EF] leading-[1.2]">

